/**
 * Renders the Pipeline view.
 */
export function Pipeline() {
  this.steps = [];
  this.pipe = function(fn) {
    this.steps.push(fn);
    return this;
  };
  this.run = async function(input) {
    let result = input;
    for (const fn of this.steps) {
      result = await fn(result);
    }
    return result;
  };
}

/**
 * Renders the Reynolds Tracker view.
 */
export function ReynoldsTracker(capacity) {
  this.capacity = capacity || 128;
  this.updateStream = function(id, status) {
    // console.log('[stub-reynolds] updateStream', id, status);
  };
  this.metrics = function() {
    return {
      reynoldsNumber: 0,
      bettiNumber: 0,
      laminarFraction: 1,
      activeStreams: 0,
      capacity: this.capacity,
      completed: 0,
      vented: 0,
      tunneled: 0,
      entangled: 0,
    };
  };
}

/**
 * Handles the gnosis frame Race workflow.
 */
export const frameRace = (...args) => Promise.resolve(args[0]?.[0]);
